/**
 * MMS Authentication Service Tests
 *
 * Tests for user authentication, JWT token management, and session lifecycle.
 *
 * @see specs/005-api.md Section 5.2 (Authentication Endpoints)
 */

import { describe, it, expect, beforeEach, mock } from 'bun:test';
import { sign } from 'hono/jwt';

// Mock the database before importing the service
const mockDb = {
  query: {
    users: {
      findFirst: mock(() => Promise.resolve(null as unknown)),
    },
    sessions: {
      findFirst: mock(() => Promise.resolve(null as unknown)),
    },
  },
  insert: mock(() => ({
    values: mock(() => Promise.resolve()),
  })),
  update: mock(() => ({
    set: mock(() => ({
      where: mock(() => Promise.resolve()),
    })),
  })),
  delete: mock(() => ({
    where: mock(() => ({
      returning: mock(() => Promise.resolve([] as unknown[])),
    })),
  })),
};

// Mock the database connection module
mock.module('../lib/db/connection', () => ({
  db: mockDb,
  withTransaction: (fn: (tx: unknown) => Promise<unknown>) => fn(mockDb),
}));

// Import after mocking
import {
  AuthService,
  getAuthService,
  type LoginRequest,
  type RefreshRequest,
  type JwtPayload,
} from './auth';
import {
  AuthenticationError,
  TokenExpiredError,
  InvalidTokenError,
} from '../lib/errors';

// =============================================================================
// Test Helpers
// =============================================================================

const JWT_SECRET = process.env.JWT_SECRET || 'mms-development-secret-change-in-production';
const REFRESH_TOKEN_SECRET = process.env.REFRESH_TOKEN_SECRET || 'mms-refresh-secret-change-in-production';
const JWT_ALGORITHM = 'HS256' as const;

const createMockUser = (overrides: Partial<{
  id: string;
  email: string;
  passwordHash: string;
  firstName: string;
  lastName: string;
  displayName: string;
  primaryDepotId: string;
  roleIds: string[];
  certifications: string[];
  isActive: boolean;
  lastLoginAt: Date | null;
  failedLoginAttempts: number;
  lockedUntil: Date | null;
}> = {}) => ({
  id: 'user-123',
  email: 'test@example.com',
  // Password hash for 'password123'
  passwordHash: '$2b$10$dummyhash.for.testing.purposes.only',
  firstName: 'Test',
  lastName: 'User',
  displayName: 'Test User',
  primaryDepotId: 'depot-1',
  roleIds: ['PLANNER'],
  certifications: [],
  isActive: true,
  lastLoginAt: null,
  failedLoginAttempts: 0,
  lockedUntil: null,
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

const createMockSession = (overrides: Partial<{
  id: string;
  userId: string;
  tokenHash: string;
  expiresAt: Date;
  lastActivityAt: Date;
  ipAddress: string;
  userAgent: string;
}> = {}) => ({
  id: 'session-123',
  userId: 'user-123',
  tokenHash: 'hashed-token',
  expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
  lastActivityAt: new Date(),
  ipAddress: '127.0.0.1',
  userAgent: 'test-agent',
  createdAt: new Date(),
  ...overrides,
});

// =============================================================================
// Tests
// =============================================================================

describe('AuthService', () => {
  let service: AuthService;

  beforeEach(() => {
    service = new AuthService();
    // Reset all mocks
    mockDb.query.users.findFirst.mockReset();
    mockDb.query.sessions.findFirst.mockReset();
    mockDb.insert.mockReset();
    mockDb.update.mockReset();
    mockDb.delete.mockReset();
  });

  describe('login', () => {
    it('should reject login for non-existent user', async () => {
      mockDb.query.users.findFirst.mockResolvedValue(null);

      const request: LoginRequest = {
        email: 'nonexistent@example.com',
        password: 'password123',
      };

      await expect(service.login(request)).rejects.toThrow(AuthenticationError);
      await expect(service.login(request)).rejects.toThrow('Invalid email or password');
    });

    it('should reject login for locked account', async () => {
      const lockedUser = createMockUser({
        lockedUntil: new Date(Date.now() + 30 * 60 * 1000), // 30 minutes from now
      });
      mockDb.query.users.findFirst.mockResolvedValue(lockedUser);

      const request: LoginRequest = {
        email: 'test@example.com',
        password: 'password123',
      };

      await expect(service.login(request)).rejects.toThrow(AuthenticationError);
      await expect(service.login(request)).rejects.toThrow(/Account is locked/);
    });

    it('should reject login for inactive account', async () => {
      const inactiveUser = createMockUser({ isActive: false });
      mockDb.query.users.findFirst.mockResolvedValue(inactiveUser);

      const request: LoginRequest = {
        email: 'test@example.com',
        password: 'password123',
      };

      await expect(service.login(request)).rejects.toThrow(AuthenticationError);
      await expect(service.login(request)).rejects.toThrow('Account is disabled');
    });

    it('should reject login with invalid password', async () => {
      const user = createMockUser();
      mockDb.query.users.findFirst.mockResolvedValue(user);
      mockDb.update.mockReturnValue({
        set: mock(() => ({
          where: mock(() => Promise.resolve()),
        })),
      });

      // Mock Bun.password.verify to return false
      const originalVerify = Bun.password.verify;
      Bun.password.verify = mock(() => Promise.resolve(false));

      try {
        const request: LoginRequest = {
          email: 'test@example.com',
          password: 'wrongpassword',
        };

        await expect(service.login(request)).rejects.toThrow(AuthenticationError);
        await expect(service.login(request)).rejects.toThrow('Invalid email or password');
      } finally {
        Bun.password.verify = originalVerify;
      }
    });

    it('should successfully login with valid credentials', async () => {
      const user = createMockUser();
      mockDb.query.users.findFirst.mockResolvedValue(user);
      mockDb.update.mockReturnValue({
        set: mock(() => ({
          where: mock(() => Promise.resolve()),
        })),
      });
      mockDb.insert.mockReturnValue({
        values: mock(() => Promise.resolve()),
      });

      // Mock Bun.password.verify to return true
      const originalVerify = Bun.password.verify;
      Bun.password.verify = mock(() => Promise.resolve(true));

      try {
        const request: LoginRequest = {
          email: 'test@example.com',
          password: 'password123',
          ipAddress: '127.0.0.1',
          userAgent: 'test-agent',
        };

        const result = await service.login(request);

        expect(result).toHaveProperty('accessToken');
        expect(result).toHaveProperty('refreshToken');
        expect(result).toHaveProperty('expiresIn');
        expect(result).toHaveProperty('user');
        expect(result.user.email).toBe('test@example.com');
        expect(result.user.roles).toEqual(['PLANNER']);
        expect(result.expiresIn).toBe(3600);
      } finally {
        Bun.password.verify = originalVerify;
      }
    });
  });

  describe('refreshToken', () => {
    it('should reject invalid refresh token', async () => {
      const request: RefreshRequest = {
        refreshToken: 'invalid-token',
      };

      await expect(service.refreshToken(request)).rejects.toThrow(InvalidTokenError);
    });

    it('should reject token with wrong type', async () => {
      // Create an access token (type is not 'refresh')
      const now = Math.floor(Date.now() / 1000);
      const payload = {
        sub: 'user-123',
        sessionId: 'session-123',
        type: 'access', // Wrong type
        iat: now,
        exp: now + 3600,
      };
      const token = await sign(payload, REFRESH_TOKEN_SECRET, JWT_ALGORITHM);

      const request: RefreshRequest = {
        refreshToken: token,
      };

      await expect(service.refreshToken(request)).rejects.toThrow(InvalidTokenError);
      await expect(service.refreshToken(request)).rejects.toThrow('Invalid token type');
    });

    it('should reject token for non-existent session', async () => {
      const now = Math.floor(Date.now() / 1000);
      const payload = {
        sub: 'user-123',
        sessionId: 'session-123',
        type: 'refresh',
        iat: now,
        exp: now + 7 * 24 * 3600,
      };
      const token = await sign(payload, REFRESH_TOKEN_SECRET, JWT_ALGORITHM);

      mockDb.query.sessions.findFirst.mockResolvedValue(null);

      const request: RefreshRequest = {
        refreshToken: token,
      };

      await expect(service.refreshToken(request)).rejects.toThrow(InvalidTokenError);
      await expect(service.refreshToken(request)).rejects.toThrow('Session not found');
