      const payload = {
        sub: 'user-123',
        sessionId: 'session-123',
        type: 'refresh',
        iat: now,
        exp: now + 7 * 24 * 3600,
      };
      const token = await sign(payload, REFRESH_TOKEN_SECRET, JWT_ALGORITHM);

      const expiredSession = createMockSession({
