/**
 * MMS Integration Routes Unit Tests
 *
 * Tests for the Integration API endpoints covering:
 * - Maximo webhook receiver (POST /integration/webhooks/maximo)
 * - Sync operations (push, pull, full)
 * - Conflict management
 * - Shadow record operations
 * - Edit validation
 *
 * Note: These tests use Bun's test framework with Hono's test client.
 * Integration tests with actual database should be in a separate test suite.
 *
 * @see src/api/routes/integration.ts
 * @see specs/007-integration.md
 */

import { describe, test, expect, beforeAll } from 'bun:test';
import { Hono } from 'hono';
import { integrationRoutes } from './integration';
import type { AppVariables } from '../types';
import { sql } from '../../lib/db/connection';

let databaseAvailable = false;

async function checkDatabaseConnection(): Promise<boolean> {
  try {
    await sql`SELECT 1`;
    return true;
  } catch {
    return false;
  }
}

describe('Integration Routes', () => {
  let app: Hono<{ Variables: AppVariables }>;

  beforeAll(async () => {
    databaseAvailable = await checkDatabaseConnection();
    app = new Hono<{ Variables: AppVariables }>();
    app.use('*', async (c, next) => {
      c.set('requestId', 'test-request-id');
      c.set('startTime', Date.now());
      await next();
    });
    app.route('/', integrationRoutes);
  });

  // ===========================================================================
  // Webhook Endpoints
  // ===========================================================================

  describe('POST /integration/webhooks/maximo', () => {
    test('should reject empty body', async () => {
      const res = await app.request('/integration/webhooks/maximo', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: '',
      });
      expect(res.status).toBe(400);

      const body = await res.json();
      expect(body.success).toBe(false);
      expect(body.error.code).toBe('VALIDATION_ERROR');
    });

    test('should reject missing event field', async () => {
      const res = await app.request('/integration/webhooks/maximo', {
